class RangeModule {
    TreeMap<Integer, Integer> map;

    public RangeModule() {
        map = new TreeMap<>();
    }

    public void addRange(int left, int right) {
        Integer l = map.floorKey(left);
        Integer r = map.ceilingKey(left);
        if (r != null && r <= right) {
            left = r;
            map.remove(r);
        }
        if (l != null && map.get(l) >= left) {
            left = l;
            map.remove(l);
        }
        l = map.floorKey(left);
        if (l != null && map.get(l) >= right) {
            map.put(left, map.get(l));
            map.remove(l);
        } else {
            map.put(left, right);
        }
    }

    public boolean queryRange(int left, int right) {
        Integer l = map.floorKey(left);
        if (l == null || map.get(l) <= left) return false;
        return map.get(l) >= right;
    }

    public void removeRange(int left, int right) {
        Integer l = map.floorKey(left);
        Integer r = map.ceilingKey(left);
        if (r != null && r < right) {
            map.put(r, left);
        }
        if (l != null && map.get(l) > left) {
            map.put(left, map.get(l));
        } else if (l != null) {
            map.remove(l);
        }
        map.subMap(left, true, right, false).clear();
    }
}
